(function (global) {
  'use strict';

  const marked = {
    _opts: {},
    setOptions(opts) {
      this._opts = { ...this._opts, ...opts };
    },
    parse(md) {
      return parseMarkdown(String(md || ''));
    },
  };

  function esc(str) {
    return str.replace(/[&<>"']/g, (ch) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[ch]));
  }

  function inline(text) {
    let out = esc(text);
    out = out.replace(/`([^`]+)`/g, '<code>$1</code>');
    out = out.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
    out = out.replace(/\*([^*]+)\*/g, '<em>$1</em>');
    out = out.replace(/\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/g, '<a href="$2" target="_blank" rel="noopener noreferrer">$1</a>');
    return out;
  }

  function parseMarkdown(markdown) {
    const lines = markdown.replace(/\r/g, '').split('\n');
    const html = [];
    let inCode = false;
    let inUl = false;
    let inOl = false;

    const closeLists = () => {
      if (inUl) {
        html.push('</ul>');
        inUl = false;
      }
      if (inOl) {
        html.push('</ol>');
        inOl = false;
      }
    };

    for (const line of lines) {
      if (/^```/.test(line)) {
        closeLists();
        if (!inCode) {
          html.push('<pre><code>');
          inCode = true;
        } else {
          html.push('</code></pre>');
          inCode = false;
        }
        continue;
      }

      if (inCode) {
        html.push(`${esc(line)}\n`);
        continue;
      }

      const h = line.match(/^(#{1,6})\s+(.*)$/);
      if (h) {
        closeLists();
        const level = h[1].length;
        html.push(`<h${level}>${inline(h[2])}</h${level}>`);
        continue;
      }

      if (/^\s*[-*]\s+/.test(line)) {
        if (!inUl) {
          closeLists();
          html.push('<ul>');
          inUl = true;
        }
        html.push(`<li>${inline(line.replace(/^\s*[-*]\s+/, ''))}</li>`);
        continue;
      }

      if (/^\s*\d+\.\s+/.test(line)) {
        if (!inOl) {
          closeLists();
          html.push('<ol>');
          inOl = true;
        }
        html.push(`<li>${inline(line.replace(/^\s*\d+\.\s+/, ''))}</li>`);
        continue;
      }

      if (!line.trim()) {
        closeLists();
        continue;
      }

      closeLists();
      html.push(`<p>${inline(line)}</p>`);
    }

    closeLists();
    if (inCode) html.push('</code></pre>');
    return html.join('');
  }

  global.marked = marked;
})(window);
